package com.google.gson.metrics;

import static org.mockito.Mockito.*;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class ParseBenchmarkTest {

  private ParseBenchmark parseBenchmark;

  @Mock
  private ParseBenchmark.Parser parserMock;

  @Mock
  private ParseBenchmark.Document documentMock;

  @BeforeEach
  void setUp() throws Exception {
    MockitoAnnotations.openMocks(this);
    parseBenchmark = new ParseBenchmark();

    // Use reflection to set private fields parser, text, document, api
    java.lang.reflect.Field parserField = ParseBenchmark.class.getDeclaredField("parser");
    parserField.setAccessible(true);
    parserField.set(parseBenchmark, parserMock);

    java.lang.reflect.Field textField = ParseBenchmark.class.getDeclaredField("text");
    textField.setAccessible(true);
    textField.set(parseBenchmark, "test text".toCharArray());

    java.lang.reflect.Field documentField = ParseBenchmark.class.getDeclaredField("document");
    documentField.setAccessible(true);
    documentField.set(parseBenchmark, documentMock);

    // Set document param field
    java.lang.reflect.Field documentParamField = ParseBenchmark.class.getDeclaredField("document");
    documentParamField.setAccessible(true);
    documentParamField.set(parseBenchmark, documentMock);

    // Set api param field to null or mock if necessary
    java.lang.reflect.Field apiField = ParseBenchmark.class.getDeclaredField("api");
    apiField.setAccessible(true);
    apiField.set(parseBenchmark, null);
  }

  @Test
  void timeParse_repsZero_noParseCall() throws Exception {
    parseBenchmark.timeParse(0);
    verify(parserMock, never()).parse(any(char[].class), any());
  }

  @Test
  void timeParse_repsPositive_parseCalledCorrectTimes() throws Exception {
    int reps = 3;
    parseBenchmark.timeParse(reps);
    verify(parserMock, times(reps)).parse(eq("test text".toCharArray()), eq(documentMock));
  }
}
